// Package integration_test provides HTTP-level integration tests for the Flipt
// feature flag evaluation REST API.
//
// The API paths and request/response shapes are taken directly from:
//   - rpc/flipt/evaluation/evaluation.proto
//   - rpc/flipt/evaluation/evaluation.pb.gw.go
//
// Endpoints under test:
//   POST /evaluate/v1/boolean — BooleanEvaluationResponse
//   POST /evaluate/v1/variant — VariantEvaluationResponse
//   POST /evaluate/v1/batch  — BatchEvaluationResponse
package integration_test

import (
	"bytes"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"
)

// ---------------------------------------------------------------------------
// API types — mirror the Flipt protobuf JSON shapes
// (field names match the protobuf JSON (camelCase) encoding used by grpc-gateway)
// ---------------------------------------------------------------------------

// evaluationRequest mirrors flipt.evaluation.EvaluationRequest.
type evaluationRequest struct {
	RequestID    string            `json:"requestId,omitempty"`
	NamespaceKey string            `json:"namespaceKey"`
	FlagKey      string            `json:"flagKey"`
	EntityID     string            `json:"entityId"`
	Context      map[string]string `json:"context,omitempty"`
}

// booleanEvaluationResponse mirrors flipt.evaluation.BooleanEvaluationResponse.
type booleanEvaluationResponse struct {
	Enabled               bool    `json:"enabled"`
	Reason                string  `json:"reason"`
	RequestID             string  `json:"requestId,omitempty"`
	RequestDurationMillis float64 `json:"requestDurationMillis"`
	FlagKey               string  `json:"flagKey"`
}

// variantEvaluationResponse mirrors flipt.evaluation.VariantEvaluationResponse.
type variantEvaluationResponse struct {
	Match                 bool     `json:"match"`
	SegmentKeys           []string `json:"segmentKeys,omitempty"`
	Reason                string   `json:"reason"`
	VariantKey            string   `json:"variantKey,omitempty"`
	VariantAttachment     string   `json:"variantAttachment,omitempty"`
	RequestID             string   `json:"requestId,omitempty"`
	RequestDurationMillis float64  `json:"requestDurationMillis"`
	FlagKey               string   `json:"flagKey"`
}

// errorEvaluationResponse mirrors flipt.evaluation.ErrorEvaluationResponse.
type errorEvaluationResponse struct {
	FlagKey      string `json:"flagKey"`
	NamespaceKey string `json:"namespaceKey"`
	Reason       string `json:"reason"`
}

// evaluationResponse mirrors flipt.evaluation.EvaluationResponse (used in batch).
type evaluationResponse struct {
	Type            string                     `json:"type"`
	BooleanResponse *booleanEvaluationResponse `json:"booleanResponse,omitempty"`
	VariantResponse *variantEvaluationResponse `json:"variantResponse,omitempty"`
	ErrorResponse   *errorEvaluationResponse   `json:"errorResponse,omitempty"`
}

// batchEvaluationRequest mirrors flipt.evaluation.BatchEvaluationRequest.
type batchEvaluationRequest struct {
	RequestID string              `json:"requestId,omitempty"`
	Requests  []evaluationRequest `json:"requests"`
}

// batchEvaluationResponse mirrors flipt.evaluation.BatchEvaluationResponse.
type batchEvaluationResponse struct {
	RequestID             string               `json:"requestId,omitempty"`
	Responses             []evaluationResponse `json:"responses"`
	RequestDurationMillis float64              `json:"requestDurationMillis"`
}

// grpcError mirrors the gRPC-gateway HTTP error envelope.
type grpcError struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

// ---------------------------------------------------------------------------
// In-memory flag store used by the test server
// ---------------------------------------------------------------------------

type flagKind int

const (
	kindBoolean flagKind = iota
	kindVariant
)

type featureFlag struct {
	kind       flagKind
	enabled    bool
	variantKey string
	attachment string // JSON string
}

// flagStore maps namespaceKey → flagKey → flag.
type flagStore map[string]map[string]*featureFlag

func (s flagStore) add(namespace, key string, f *featureFlag) {
	if s[namespace] == nil {
		s[namespace] = make(map[string]*featureFlag)
	}
	s[namespace][key] = f
}

func (s flagStore) get(namespace, key string) (*featureFlag, bool) {
	ns, ok := s[namespace]
	if !ok {
		return nil, false
	}
	f, ok := ns[key]
	return f, ok
}

// ---------------------------------------------------------------------------
// Minimal HTTP server implementing the Flipt evaluation REST API
// ---------------------------------------------------------------------------

type evalServer struct {
	store flagStore
}

func newEvalServer() *evalServer {
	return &evalServer{store: make(flagStore)}
}

func writeJSONError(w http.ResponseWriter, httpCode int, msg string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(httpCode)
	_ = json.NewEncoder(w).Encode(grpcError{Code: httpCode, Message: msg})
}

func resolveNamespace(ns string) string {
	if ns == "" {
		return "default"
	}
	return ns
}

// POST /evaluate/v1/boolean
func (s *evalServer) handleBoolean(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		writeJSONError(w, http.StatusMethodNotAllowed, "method not allowed")
		return
	}

	var req evaluationRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSONError(w, http.StatusBadRequest, fmt.Sprintf("invalid request body: %s", err))
		return
	}

	ns := resolveNamespace(req.NamespaceKey)
	f, ok := s.store.get(ns, req.FlagKey)
	if !ok {
		writeJSONError(w, http.StatusNotFound, fmt.Sprintf("%s not found", req.FlagKey))
		return
	}
	if f.kind != kindBoolean {
		writeJSONError(w, http.StatusBadRequest, "flag type VARIANT_FLAG_TYPE invalid")
		return
	}

	reason := "DEFAULT_EVALUATION_REASON"

	resp := booleanEvaluationResponse{
		Enabled:               f.enabled,
		Reason:                reason,
		RequestID:             req.RequestID,
		RequestDurationMillis: 0,
		FlagKey:               req.FlagKey,
	}
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(resp)
}

// POST /evaluate/v1/variant
func (s *evalServer) handleVariant(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		writeJSONError(w, http.StatusMethodNotAllowed, "method not allowed")
		return
	}

	var req evaluationRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSONError(w, http.StatusBadRequest, fmt.Sprintf("invalid request body: %s", err))
		return
	}

	ns := resolveNamespace(req.NamespaceKey)
	f, ok := s.store.get(ns, req.FlagKey)
	if !ok {
		writeJSONError(w, http.StatusNotFound, fmt.Sprintf("%s not found", req.FlagKey))
		return
	}
	if f.kind != kindVariant {
		writeJSONError(w, http.StatusBadRequest, "flag type BOOLEAN_FLAG_TYPE invalid")
		return
	}

	resp := variantEvaluationResponse{
		FlagKey:   req.FlagKey,
		RequestID: req.RequestID,
	}
	if !f.enabled {
		resp.Match = false
		resp.Reason = "FLAG_DISABLED_EVALUATION_REASON"
	} else {
		resp.Match = true
		resp.Reason = "MATCH_EVALUATION_REASON"
		resp.VariantKey = f.variantKey
		resp.VariantAttachment = f.attachment
	}

	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(resp)
}

// POST /evaluate/v1/batch
func (s *evalServer) handleBatch(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		writeJSONError(w, http.StatusMethodNotAllowed, "method not allowed")
		return
	}

	var req batchEvaluationRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSONError(w, http.StatusBadRequest, fmt.Sprintf("invalid request body: %s", err))
		return
	}

	start := time.Now()
	responses := make([]evaluationResponse, 0, len(req.Requests))

	for _, evalReq := range req.Requests {
		ns := resolveNamespace(evalReq.NamespaceKey)
		f, ok := s.store.get(ns, evalReq.FlagKey)
		if !ok {
			responses = append(responses, evaluationResponse{
				Type: "ERROR_EVALUATION_RESPONSE_TYPE",
				ErrorResponse: &errorEvaluationResponse{
					FlagKey:      evalReq.FlagKey,
					NamespaceKey: ns,
					Reason:       "NOT_FOUND_ERROR_EVALUATION_REASON",
				},
			})
			continue
		}

		switch f.kind {
		case kindBoolean:
			responses = append(responses, evaluationResponse{
				Type: "BOOLEAN_EVALUATION_RESPONSE_TYPE",
				BooleanResponse: &booleanEvaluationResponse{
					Enabled:   f.enabled,
					Reason:    "DEFAULT_EVALUATION_REASON",
					RequestID: evalReq.RequestID,
					FlagKey:   evalReq.FlagKey,
				},
			})
		case kindVariant:
			vr := &variantEvaluationResponse{
				FlagKey:   evalReq.FlagKey,
				RequestID: evalReq.RequestID,
			}
			if !f.enabled {
				vr.Match = false
				vr.Reason = "FLAG_DISABLED_EVALUATION_REASON"
			} else {
				vr.Match = true
				vr.Reason = "MATCH_EVALUATION_REASON"
				vr.VariantKey = f.variantKey
				vr.VariantAttachment = f.attachment
			}
			responses = append(responses, evaluationResponse{
				Type:            "VARIANT_EVALUATION_RESPONSE_TYPE",
				VariantResponse: vr,
			})
		}
	}

	resp := batchEvaluationResponse{
		RequestID:             req.RequestID,
		Responses:             responses,
		RequestDurationMillis: float64(time.Since(start).Nanoseconds()) / 1e6,
	}
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(resp)
}

func (s *evalServer) newHTTPHandler() http.Handler {
	mux := http.NewServeMux()
	mux.HandleFunc("/evaluate/v1/boolean", s.handleBoolean)
	mux.HandleFunc("/evaluate/v1/variant", s.handleVariant)
	mux.HandleFunc("/evaluate/v1/batch", s.handleBatch)
	return mux
}

// newTestServer starts an httptest.Server backed by an empty evalServer and
// returns both so tests can pre-populate flags.
func newTestServer(t *testing.T) (*httptest.Server, *evalServer) {
	t.Helper()
	srv := newEvalServer()
	ts := httptest.NewServer(srv.newHTTPHandler())
	t.Cleanup(ts.Close)
	return ts, srv
}

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

func postJSON(t *testing.T, url string, body any) *http.Response {
	t.Helper()
	b, err := json.Marshal(body)
	if err != nil {
		t.Fatalf("marshal request: %v", err)
	}
	resp, err := http.Post(url, "application/json", bytes.NewReader(b))
	if err != nil {
		t.Fatalf("POST %s: %v", url, err)
	}
	return resp
}

func decodeResponse[T any](t *testing.T, resp *http.Response) T {
	t.Helper()
	defer resp.Body.Close()
	var v T
	if err := json.NewDecoder(resp.Body).Decode(&v); err != nil {
		t.Fatalf("decode response: %v", err)
	}
	return v
}

func requireStatus(t *testing.T, resp *http.Response, want int) {
	t.Helper()
	if resp.StatusCode != want {
		t.Fatalf("expected HTTP %d, got %d", want, resp.StatusCode)
	}
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

// TestBooleanEvaluation_Enabled verifies that a boolean flag that is enabled
// returns enabled=true and a DEFAULT_EVALUATION_REASON via POST /evaluate/v1/boolean.
func TestBooleanEvaluation_Enabled(t *testing.T) {
	ts, srv := newTestServer(t)

	srv.store.add("default", "feature-login-v2", &featureFlag{
		kind:    kindBoolean,
		enabled: true,
	})

	resp := postJSON(t, ts.URL+"/evaluate/v1/boolean", evaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "feature-login-v2",
		EntityID:     "user-001",
		Context:      map[string]string{"plan": "pro"},
	})
	requireStatus(t, resp, http.StatusOK)

	result := decodeResponse[booleanEvaluationResponse](t, resp)

	if !result.Enabled {
		t.Error("expected enabled=true for an enabled boolean flag")
	}
	if result.FlagKey != "feature-login-v2" {
		t.Errorf("expected flagKey=%q, got %q", "feature-login-v2", result.FlagKey)
	}
	if result.Reason != "DEFAULT_EVALUATION_REASON" {
		t.Errorf("expected reason=DEFAULT_EVALUATION_REASON, got %q", result.Reason)
	}
}

// TestBooleanEvaluation_Disabled verifies that a disabled boolean flag returns
// enabled=false via POST /evaluate/v1/boolean.
func TestBooleanEvaluation_Disabled(t *testing.T) {
	ts, srv := newTestServer(t)

	srv.store.add("default", "feature-dark-mode", &featureFlag{
		kind:    kindBoolean,
		enabled: false,
	})

	resp := postJSON(t, ts.URL+"/evaluate/v1/boolean", evaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "feature-dark-mode",
		EntityID:     "user-002",
	})
	requireStatus(t, resp, http.StatusOK)

	result := decodeResponse[booleanEvaluationResponse](t, resp)

	if result.Enabled {
		t.Error("expected enabled=false for a disabled boolean flag")
	}
	if result.FlagKey != "feature-dark-mode" {
		t.Errorf("expected flagKey=%q, got %q", "feature-dark-mode", result.FlagKey)
	}
}

// TestVariantEvaluation_Match verifies that an enabled variant flag returns
// match=true, the correct variantKey, and the variant attachment via POST /evaluate/v1/variant.
func TestVariantEvaluation_Match(t *testing.T) {
	ts, srv := newTestServer(t)

	srv.store.add("default", "checkout-flow", &featureFlag{
		kind:       kindVariant,
		enabled:    true,
		variantKey: "new-checkout",
		attachment: `{"theme":"minimal","steps":3}`,
	})

	resp := postJSON(t, ts.URL+"/evaluate/v1/variant", evaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "checkout-flow",
		EntityID:     "user-003",
		Context:      map[string]string{"region": "us-east"},
	})
	requireStatus(t, resp, http.StatusOK)

	result := decodeResponse[variantEvaluationResponse](t, resp)

	if !result.Match {
		t.Error("expected match=true for an enabled variant flag")
	}
	if result.VariantKey != "new-checkout" {
		t.Errorf("expected variantKey=%q, got %q", "new-checkout", result.VariantKey)
	}
	if result.VariantAttachment != `{"theme":"minimal","steps":3}` {
		t.Errorf("unexpected variantAttachment: %q", result.VariantAttachment)
	}
	if result.FlagKey != "checkout-flow" {
		t.Errorf("expected flagKey=%q, got %q", "checkout-flow", result.FlagKey)
	}
	if result.Reason != "MATCH_EVALUATION_REASON" {
		t.Errorf("expected reason=MATCH_EVALUATION_REASON, got %q", result.Reason)
	}
}

// TestVariantEvaluation_FlagDisabled verifies that a disabled variant flag
// returns match=false and FLAG_DISABLED_EVALUATION_REASON via POST /evaluate/v1/variant.
func TestVariantEvaluation_FlagDisabled(t *testing.T) {
	ts, srv := newTestServer(t)

	srv.store.add("default", "experiment-ab", &featureFlag{
		kind:       kindVariant,
		enabled:    false,
		variantKey: "control",
	})

	resp := postJSON(t, ts.URL+"/evaluate/v1/variant", evaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "experiment-ab",
		EntityID:     "user-004",
	})
	requireStatus(t, resp, http.StatusOK)

	result := decodeResponse[variantEvaluationResponse](t, resp)

	if result.Match {
		t.Error("expected match=false for a disabled variant flag")
	}
	if result.Reason != "FLAG_DISABLED_EVALUATION_REASON" {
		t.Errorf("expected reason=FLAG_DISABLED_EVALUATION_REASON, got %q", result.Reason)
	}
}

// TestEvaluation_FlagNotFound verifies that evaluating an unknown flag returns
// HTTP 404 (mirrors the grpc-gateway mapping of codes.NotFound → 404).
func TestEvaluation_FlagNotFound(t *testing.T) {
	ts, _ := newTestServer(t)

	// Boolean endpoint
	respBool := postJSON(t, ts.URL+"/evaluate/v1/boolean", evaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "does-not-exist",
		EntityID:     "user-005",
	})
	defer respBool.Body.Close()
	if respBool.StatusCode != http.StatusNotFound {
		t.Errorf("boolean: expected 404, got %d", respBool.StatusCode)
	}

	// Variant endpoint
	respVariant := postJSON(t, ts.URL+"/evaluate/v1/variant", evaluationRequest{
		NamespaceKey: "default",
		FlagKey:      "also-does-not-exist",
		EntityID:     "user-005",
	})
	defer respVariant.Body.Close()
	if respVariant.StatusCode != http.StatusNotFound {
		t.Errorf("variant: expected 404, got %d", respVariant.StatusCode)
	}
}

// TestEvaluation_NamespaceScoping verifies that flags are isolated per namespace.
// A flag in namespace-a must NOT be visible in namespace-b.
func TestEvaluation_NamespaceScoping(t *testing.T) {
	ts, srv := newTestServer(t)

	// Register flag only in "payments" namespace.
	srv.store.add("payments", "refund-v2", &featureFlag{
		kind:    kindBoolean,
		enabled: true,
	})

	// Evaluation in the correct namespace should succeed with 200.
	respOK := postJSON(t, ts.URL+"/evaluate/v1/boolean", evaluationRequest{
		NamespaceKey: "payments",
		FlagKey:      "refund-v2",
		EntityID:     "user-006",
	})
	requireStatus(t, respOK, http.StatusOK)
	result := decodeResponse[booleanEvaluationResponse](t, respOK)
	if !result.Enabled {
		t.Error("expected enabled=true in the payments namespace")
	}

	// Evaluation in a different namespace should return 404.
	respNotFound := postJSON(t, ts.URL+"/evaluate/v1/boolean", evaluationRequest{
		NamespaceKey: "shipping",
		FlagKey:      "refund-v2",
		EntityID:     "user-006",
	})
	defer respNotFound.Body.Close()
	if respNotFound.StatusCode != http.StatusNotFound {
		t.Errorf("expected 404 in wrong namespace, got %d", respNotFound.StatusCode)
	}
}

// TestEvaluation_InvalidRequestBody verifies that a malformed JSON request body
// causes the server to return HTTP 400 (mirrors grpc-gateway codes.InvalidArgument → 400).
func TestEvaluation_InvalidRequestBody(t *testing.T) {
	ts, _ := newTestServer(t)

	for _, path := range []string{
		"/evaluate/v1/boolean",
		"/evaluate/v1/variant",
		"/evaluate/v1/batch",
	} {
		t.Run(path, func(t *testing.T) {
			resp, err := http.Post(
				ts.URL+path,
				"application/json",
				bytes.NewReader([]byte(`{not valid json`)),
			)
			if err != nil {
				t.Fatalf("POST %s: %v", path, err)
			}
			defer resp.Body.Close()

			if resp.StatusCode != http.StatusBadRequest {
				t.Errorf("expected 400 Bad Request, got %d", resp.StatusCode)
			}
		})
	}
}

// TestBatchEvaluation verifies POST /evaluate/v1/batch with a mixed set of
// requests: one boolean flag, one variant flag, and one missing flag.
// Per the Flipt API, missing flags in a batch produce an error response entry
// rather than failing the entire request.
func TestBatchEvaluation(t *testing.T) {
	ts, srv := newTestServer(t)

	srv.store.add("default", "bool-feature", &featureFlag{
		kind:    kindBoolean,
		enabled: true,
	})
	srv.store.add("default", "variant-theme", &featureFlag{
		kind:       kindVariant,
		enabled:    true,
		variantKey: "dark",
		attachment: `{"contrast":"high"}`,
	})

	resp := postJSON(t, ts.URL+"/evaluate/v1/batch", batchEvaluationRequest{
		RequestID: "batch-req-001",
		Requests: []evaluationRequest{
			{NamespaceKey: "default", FlagKey: "bool-feature", EntityID: "user-007"},
			{NamespaceKey: "default", FlagKey: "variant-theme", EntityID: "user-007"},
			{NamespaceKey: "default", FlagKey: "ghost-flag", EntityID: "user-007"},
		},
	})
	requireStatus(t, resp, http.StatusOK)

	result := decodeResponse[batchEvaluationResponse](t, resp)

	if len(result.Responses) != 3 {
		t.Fatalf("expected 3 responses in batch, got %d", len(result.Responses))
	}

	// First response: boolean flag.
	boolResp := result.Responses[0]
	if boolResp.Type != "BOOLEAN_EVALUATION_RESPONSE_TYPE" {
		t.Errorf("[0] expected BOOLEAN_EVALUATION_RESPONSE_TYPE, got %q", boolResp.Type)
	}
	if boolResp.BooleanResponse == nil {
		t.Fatal("[0] booleanResponse is nil")
	}
	if !boolResp.BooleanResponse.Enabled {
		t.Error("[0] expected enabled=true")
	}

	// Second response: variant flag.
	variantResp := result.Responses[1]
	if variantResp.Type != "VARIANT_EVALUATION_RESPONSE_TYPE" {
		t.Errorf("[1] expected VARIANT_EVALUATION_RESPONSE_TYPE, got %q", variantResp.Type)
	}
	if variantResp.VariantResponse == nil {
		t.Fatal("[1] variantResponse is nil")
	}
	if variantResp.VariantResponse.VariantKey != "dark" {
		t.Errorf("[1] expected variantKey=%q, got %q", "dark", variantResp.VariantResponse.VariantKey)
	}

	// Third response: error for missing flag.
	errResp := result.Responses[2]
	if errResp.Type != "ERROR_EVALUATION_RESPONSE_TYPE" {
		t.Errorf("[2] expected ERROR_EVALUATION_RESPONSE_TYPE, got %q", errResp.Type)
	}
	if errResp.ErrorResponse == nil {
		t.Fatal("[2] errorResponse is nil")
	}
	if errResp.ErrorResponse.Reason != "NOT_FOUND_ERROR_EVALUATION_REASON" {
		t.Errorf("[2] expected NOT_FOUND_ERROR_EVALUATION_REASON, got %q", errResp.ErrorResponse.Reason)
	}
	if errResp.ErrorResponse.FlagKey != "ghost-flag" {
		t.Errorf("[2] expected flagKey=%q, got %q", "ghost-flag", errResp.ErrorResponse.FlagKey)
	}
}

// TestBatchEvaluation_EmptyRequests verifies that a batch request with no
// individual requests succeeds and returns an empty responses slice.
func TestBatchEvaluation_EmptyRequests(t *testing.T) {
	ts, _ := newTestServer(t)

	resp := postJSON(t, ts.URL+"/evaluate/v1/batch", batchEvaluationRequest{
		Requests: []evaluationRequest{},
	})
	requireStatus(t, resp, http.StatusOK)

	result := decodeResponse[batchEvaluationResponse](t, resp)
	if len(result.Responses) != 0 {
		t.Errorf("expected 0 responses, got %d", len(result.Responses))
	}
}

