56: func handleError(ctx context.Context, err error) error {
57: 	if err == nil {
58: 		return nil
59: 	}
60: 
61: 	metrics.ErrorsTotal.Add(ctx, 1)
62: 
63: 	// given already a *status.Error then forward unchanged
64: 	if _, ok := status.FromError(err); ok {
65: 		return err
66: 	}
67: 
68: 	if errors.Is(err, context.Canceled) {
69: 		return status.Error(codes.Canceled, err.Error())
70: 	}
71: 
72: 	if errors.Is(err, context.DeadlineExceeded) {
73: 		return status.Error(codes.DeadlineExceeded, err.Error())
74: 	}
75: 
76: 	code := codes.Internal
77: 	switch {
78: 	case errs.AsMatch[errs.ErrNotFound](err):
79: 		code = codes.NotFound
80: 	case errs.AsMatch[errs.ErrInvalid](err),
81: 		errs.AsMatch[errs.ErrValidation](err):
82: 		code = codes.InvalidArgument
83: 	case errs.AsMatch[errs.ErrUnauthenticated](err):
84: 		code = codes.Unauthenticated
85: 	case errs.AsMatch[errs.ErrUnauthorized](err):
86: 		code = codes.PermissionDenied
87: 	case errs.AsMatch[errs.ErrAlreadyExists](err):
88: 		code = codes.AlreadyExists
89: 	case errs.AsMatch[errs.ErrConflict](err):
90: 		code = codes.Aborted
91: 	case errs.AsMatch[errs.ErrNotImplemented](err):
92: 		code = codes.Unimplemented
93: 	case errs.AsMatch[errs.ErrNotModified](err):
94: 		// special case: only supported via HTTP / Gateway
95: 		// we set the response to OK, but override the http status code to 304 (Not Modified)
96: 		code = codes.OK
97: 		_ = grpc.SetHeader(ctx, metadata.Pairs("x-http-code", "304"))
98: 	}
99: 
100: 	return status.Error(code, err.Error())
101: }
