115: // FliptHeadersUnaryInterceptor intercepts incoming requests and adds the flipt environment and namespace to the context.
116: func FliptHeadersUnaryInterceptor(logger *zap.Logger) grpc.UnaryServerInterceptor {
117: 	return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
118: 		md, ok := metadata.FromIncomingContext(ctx)
119: 		if !ok {
120: 			logger.Debug("no metadata found in context")
121: 			return handler(ctx, req)
122: 		}
123: 
124: 		ctx = contextWithMetadata(ctx, md, logger)
125: 		return handler(ctx, req)
126: 	}
