129: // FliptHeadersStreamInterceptor intercepts incoming requests and adds the flipt environment and namespace to the context.
130: func FliptHeadersStreamInterceptor(logger *zap.Logger) grpc.StreamServerInterceptor {
131: 	return func(srv any, stream grpc.ServerStream, info *grpc.StreamServerInfo, handler grpc.StreamHandler) error {
132: 		md, ok := metadata.FromIncomingContext(stream.Context())
133: 		if !ok {
134: 			logger.Debug("no metadata found in context")
135: 			return handler(srv, stream)
136: 		}
137: 
138: 		ctx := contextWithMetadata(stream.Context(), md, logger)
139: 		return handler(srv, &grpcmiddleware.WrappedServerStream{
