147: func contextWithMetadata(ctx context.Context, md metadata.MD, logger *zap.Logger) context.Context {
148: 	if fliptEnvironment := md.Get(common.HeaderFliptEnvironment); len(fliptEnvironment) > 0 {
149: 		environment := fliptEnvironment[0]
150: 		if environment != "" {
