156: 	if fliptNamespace := md.Get(common.HeaderFliptNamespace); len(fliptNamespace) > 0 {
157: 		namespace := fliptNamespace[0]
158: 		if namespace != "" {
159: 			logger.Debug("setting flipt namespace in request context", zap.String("namespace", namespace))
160: 			ctx = cctx.WithFliptNamespace(ctx, namespace)
