174: 		if r, ok := req.(*evaluation.EvaluationRequest); ok {
175: 			environmentKey, _ := cctx.FliptEnvironmentFromContext(ctx)
176: 			namespaceKey, _ := cctx.FliptNamespaceFromContext(ctx)
177: 			r.SetEnvironmentKeyIfNotBlank(environmentKey)
178: 			r.SetNamespaceKeyIfNotBlank(namespaceKey)
