// TestBatchEvaluation verifies POST /evaluate/v1/batch with a mixed set of
// requests: one boolean flag, one variant flag, and one missing flag.
// Per the Flipt API, missing flags in a batch produce an error response entry
// rather than failing the entire request.
func TestBatchEvaluation(t *testing.T) {
	ts, srv := newTestServer(t)

	srv.store.add("default", "bool-feature", &featureFlag{
		kind:    kindBoolean,
		enabled: true,
	})
	srv.store.add("default", "variant-theme", &featureFlag{
		kind:       kindVariant,
		enabled:    true,
		variantKey: "dark",
		attachment: `{"contrast":"high"}`,
	})

	resp := postJSON(t, ts.URL+"/evaluate/v1/batch", batchEvaluationRequest{
		RequestID: "batch-req-001",
		Requests: []evaluationRequest{
			{NamespaceKey: "default", FlagKey: "bool-feature", EntityID: "user-007"},
			{NamespaceKey: "default", FlagKey: "variant-theme", EntityID: "user-007"},
			{NamespaceKey: "default", FlagKey: "ghost-flag", EntityID: "user-007"},
		},
	})
	requireStatus(t, resp, http.StatusOK)

	result := decodeResponse[batchEvaluationResponse](t, resp)

	if len(result.Responses) != 3 {
		t.Fatalf("expected 3 responses in batch, got %d", len(result.Responses))
	}

	// First response: boolean flag.
	boolResp := result.Responses[0]
	if boolResp.Type != "BOOLEAN_EVALUATION_RESPONSE_TYPE" {
		t.Errorf("[0] expected BOOLEAN_EVALUATION_RESPONSE_TYPE, got %q", boolResp.Type)
	}
	if boolResp.BooleanResponse == nil {
		t.Fatal("[0] booleanResponse is nil")
	}
	if !boolResp.BooleanResponse.Enabled {
		t.Error("[0] expected enabled=true")
	}

	// Second response: variant flag.
